-- Generated seed for authors and works
create extension if not exists pgcrypto;

insert into public.authors (slug, name, period, movement, biography, themes, image_url, access_level) values
('iakob-khutsesi', 'იაკობ ხუცესი', 'old-georgian', 'ჰაგიოგრაფია', 'V საუკუნის ქართველი ჰაგიოგრაფი. „შუშანიკის წამება“ ქართული მწერლობის უძველეს ნიმუშად მიიჩნევა.', ARRAY['რწმენა', 'პიროვნული სიმტკიცე', 'ძალაუფლება']::text[], null, 'free'),
('ioane-sabanisdze', 'იოანე საბანისძე', 'old-georgian', 'ჰაგიოგრაფია', 'VIII საუკუნის მწერალი, რომელმაც აბო თბილელის მოწამეობრივი ისტორია თბილისის მრავალეროვან გარემოს დაუკავშირა.', ARRAY['რწმენა', 'იდენტობა', 'ქალაქი და საზოგადოება']::text[], null, 'free'),
('giorgi-merchule', 'გიორგი მერჩულე', 'old-georgian', 'ჰაგიოგრაფია', 'X საუკუნის ავტორი. მისი ტექსტი გრიგოლ ხანძთელის ცხოვრებასთან ერთად ქართული კულტურული სივრცის იდეას აყალიბებს.', ARRAY['სულიერი მოღვაწეობა', 'განათლება', 'ქართული კულტურული სივრცე']::text[], null, 'free'),
('shota-rustaveli', 'შოთა რუსთაველი', 'renaissance', 'ქართული რენესანსი', 'ქართული შუასაუკუნეების პოეზიის უდიდესი წარმომადგენელი. „ვეფხისტყაოსანი“ მეგობრობის, სიყვარულისა და მმართველობის ეთიკას აერთიანებს.', ARRAY['მეგობრობა', 'სიყვარული', 'ზნეობა', 'მმართველობა']::text[], null, 'free'),
('sulkhan-saba-orbeliani', 'სულხან-საბა ორბელიანი', 'old-georgian', 'სიბრძნე-სწავლებითი პროზა', 'მწერალი, დიპლომატი და ლექსიკოგრაფი. მისი იგავური პროზა მორალურ დაკვირვებასა და საზოგადოებრივ კრიტიკას ეფუძნება.', ARRAY['სიბრძნე', 'სიცრუე', 'მორალი']::text[], null, 'free'),
('davit-guramishvili', 'დავით გურამიშვილი', 'old-georgian', 'კლასიკური პოეზია', 'XVIII საუკუნის პოეტი. „დავითიანი“ პირად ბიოგრაფიას, ისტორიულ მეხსიერებასა და რელიგიურ აზროვნებას აერთიანებს.', ARRAY['ისტორია', 'რწმენა', 'თვითშემეცნება']::text[], null, 'free'),
('alexandre-chavchavadze', 'ალექსანდრე ჭავჭავაძე', 'romanticism', 'რომანტიზმი', 'ქართული რომანტიზმის ერთ-ერთი დამწყები. მის პოეზიაში პირადი განცდა და ისტორიული მეხსიერება თანაარსებობს.', ARRAY['სევდა', 'ბუნება', 'ისტორიული მეხსიერება']::text[], null, 'free'),
('grigol-orbeliani', 'გრიგოლ ორბელიანი', 'romanticism', 'რომანტიზმი', 'რომანტიკოსი პოეტი, რომლის ტექსტებში ეროვნული წარსული, თაობათა დაპირისპირება და ისტორიული იდეალი იკითხება.', ARRAY['წარსული', 'თაობები', 'ეროვნული იდეალი']::text[], null, 'free'),
('nikoloz-baratashvili', 'ნიკოლოზ ბარათაშვილი', 'romanticism', 'რომანტიზმი', 'ქართული რომანტიზმის ცენტრალური ფიგურა. მისი ლირიკა თავისუფლების, ბედისწერისა და მარტოობის განცდას უკავშირდება.', ARRAY['თავისუფლება', 'ბედისწერა', 'მარტოობა', 'ეროვნული ტკივილი']::text[], null, 'free'),
('ilia-chavchavadze', 'ილია ჭავჭავაძე', 'realism', 'რეალიზმი', 'მწერალი და საზოგადო მოღვაწე. მის ტექსტებში ეროვნული თვითშეგნება, განათლება და სოციალური პასუხისმგებლობა მთავარ ღერძს ქმნის.', ARRAY['განათლება', 'სამართლიანობა', 'ეროვნული თვითშეგნება', 'სოციალური კრიტიკა']::text[], null, 'free'),
('akaki-tsereteli', 'აკაკი წერეთელი', 'realism', 'რეალიზმი', 'პოეტი და საზოგადო მოღვაწე. მისი საგამოცდო ტექსტები პატრიოტულ მოტივს, ზნეობრივ არჩევანსა და ისტორიულ თემებს უკავშირდება.', ARRAY['პატრიოტიზმი', 'ზნეობა', 'ისტორია']::text[], null, 'free'),
('alexandre-qazbegi', 'ალექსანდრე ყაზბეგი', 'realism', 'რეალიზმი', 'პროზაიკოსი, რომლის ტექსტებში მთის საზოგადოება, პიროვნული ღირსება და ტრადიციის ძალა ჩანს.', ARRAY['ღირსება', 'ტრადიცია', 'პიროვნება და საზოგადოება']::text[], null, 'free'),
('vazha-pshavela', 'ვაჟა-ფშაველა', 'realism', 'რეალიზმი / ჰუმანისტური პროზა და პოეზია', 'ქართული ლიტერატურის უმნიშვნელოვანესი ავტორი. მის ტექსტებში პიროვნება თემის წესს, ჰუმანიზმსა და ღირსებას შორის არჩევანს აკეთებს.', ARRAY['პიროვნება და თემი', 'ჰუმანიზმი', 'ღირსება', 'თავისუფალი არჩევანი']::text[], null, 'free'),
('davit-kldiashvili', 'დავით კლდიაშვილი', 'realism', 'რეალიზმი', 'ქართული რეალისტური პროზის ავტორი. მისი ტექსტები გაღარიბებული აზნაურობის ყოფასა და სოციალური ცვლილებების ტრაგიკომიკურ მხარეს აჩვენებს.', ARRAY['სოციალური კრიზისი', 'ოჯახი', 'ირონია']::text[], null, 'free'),
('niko-lortkipanidze', 'ნიკო ლორთქიფანიძე', 'modernism', 'იმპრესიონიზმი / მოდერნიზმი', 'მოდერნისტული პროზის წარმომადგენელი. მის ტექსტებში მოკლე ფორმა, განწყობა და ფსიქოლოგიური დეტალი განსაკუთრებულ მნიშვნელობას იღებს.', ARRAY['განწყობა', 'ფსიქოლოგიური დეტალი', 'სოციალური ფონები']::text[], null, 'free'),
('konstantine-gamsakhurdia', 'კონსტანტინე გამსახურდია', 'modernism', 'მოდერნიზმი', 'ისტორიული რომანის ოსტატი. „დიდოსტატის მარჯვენა“ ხელოვნების, ძალაუფლებისა და პიროვნული ღირსების საკითხებს აყენებს.', ARRAY['ხელოვნება', 'ძალაუფლება', 'ღირსება']::text[], null, 'free'),
('mikheil-javakhishvili', 'მიხეილ ჯავახიშვილი', 'modernism', 'მოდერნიზმი / სოციალური პროზა', 'XX საუკუნის პროზაიკოსი. მისი ტექსტები სოციალურ ძალადობას, პიროვნების დეგრადაციასა და მორალურ არჩევანს იკვლევს.', ARRAY['სოციალური ძალადობა', 'მორალი', 'პიროვნების კრიზისი']::text[], null, 'free'),
('leo-kiacheli', 'ლეო ქიაჩელი', 'modernism', 'მოდერნიზმი', 'პროზაიკოსი, რომლის ტექსტებში ისტორიული კონფლიქტი და ადამიანური ღირსება საგამოცდო ანალიზის მთავარ საყრდენად იქცევა.', ARRAY['კონფლიქტი', 'ღირსება', 'ისტორიული გარემო']::text[], null, 'free'),
('polikarpe-kakabadze', 'პოლიკარპე კაკაბაძე', 'modernism', 'სატირული დრამა', 'დრამატურგი. „ყვარყვარე თუთაბერი“ პოლიტიკური სატირისა და ძალაუფლების აბსურდის მაგალითია.', ARRAY['სატირა', 'ძალაუფლება', 'ფარსი']::text[], null, 'free'),
('galaktion-tabidze', 'გალაკტიონ ტაბიძე', 'modernism', 'სიმბოლიზმი / მოდერნიზმი', 'ქართული ლირიკის გამორჩეული ავტორი. მის პოეზიაში მუსიკალურობა, სიმბოლო და შინაგანი მარტოობა ცენტრალურია.', ARRAY['მარტოობა', 'სიმბოლო', 'მუსიკალურობა', 'სიკვდილის განცდა']::text[], null, 'free'),
('titsian-tabidze', 'ტიციან ტაბიძე', 'modernism', 'სიმბოლიზმი', 'ცისფერყანწელი პოეტი. მისი ტექსტები სიმბოლისტურ სახეებით, ისტორიული განწყობითა და პოეტური კულტურით იკითხება.', ARRAY['სიმბოლო', 'ისტორია', 'პოეტური სახე']::text[], null, 'free'),
('paolo-iashvili', 'პაოლო იაშვილი', 'modernism', 'სიმბოლიზმი', 'ცისფერყანწელთა თაობის პოეტი. საგამოცდოდ მნიშვნელოვანია პოეზიის დანიშნულებისა და პოეტის თვითშეგნების გააზრება.', ARRAY['პოეზია', 'პოეტის როლი', 'მოდერნისტული ხედვა']::text[], null, 'free'),
('giorgi-leonidze', 'გიორგი ლეონიძე', 'modernism', 'მოდერნიზმი', 'პოეტი, რომლის ტექსტებში ისტორიული მეხსიერება, ფერი და ემოციური ინტონაცია გამოკვეთილია.', ARRAY['ისტორიული მეხსიერება', 'სიყვარული', 'პოეტური სახე']::text[], null, 'free'),
('guram-rcheulishvili', 'გურამ რჩეულიშვილი', 'contemporary', 'თანამედროვე პროზა', 'XX საუკუნის პროზაიკოსი. მისი ტექსტები ახალგაზრდა ადამიანის შინაგან დაძაბულობასა და ცხოვრების ნამდვილობის ძიებას უკავშირდება.', ARRAY['თავისუფლება', 'თვითძიება', 'თანამედროვე ადამიანი']::text[], null, 'free'),
('ana-kalandadze', 'ანა კალანდაძე', 'contemporary', 'თანამედროვე პოეზია', 'ლირიკოსი პოეტი. მისი ტექსტები ინტიმურ ტონს, სიმბოლურ ხატებსა და ღრმა ემოციურ სიზუსტეს ეყრდნობა.', ARRAY['ლირიკული ხმა', 'სიკვდილი', 'შინაგანი სინათლე']::text[], null, 'free'),
('jemal-karchkhadze', 'ჯემალ ქარჩხაძე', 'contemporary', 'თანამედროვე პროზა', 'თანამედროვე ქართული პროზის ავტორი. „იგი“ ადამიანის წარმოშობის, ცნობიერებისა და ძალაუფლების თემებს განიხილავს.', ARRAY['ცნობიერება', 'ძალაუფლება', 'ადამიანის დასაწყისი']::text[], null, 'free'),
('guram-dochanashvili', 'გურამ დოჩანაშვილი', 'contemporary', 'თანამედროვე პროზა', 'პროზაიკოსი, რომლის ტექსტებში ლიტერატურის ძალა, მკითხველის გამოცდილება და თავისუფალი წარმოსახვა ცენტრალურია.', ARRAY['ლიტერატურის სიყვარული', 'თავისუფლება', 'მკითხველი']::text[], null, 'free')
on conflict (slug) do update set
  name = excluded.name,
  period = excluded.period,
  movement = excluded.movement,
  biography = excluded.biography,
  themes = excluded.themes,
  image_url = excluded.image_url,
  access_level = excluded.access_level;

insert into public.works (slug, title, author_id, genre, summary, summary_chapters, plan, analysis, quiz_data, themes, characters, symbols, exam_tips, access_level)
select seed.slug, seed.title, a.id, seed.genre, seed.summary, seed.summary_chapters, seed.plan, seed.analysis, seed.quiz_data, seed.themes, seed.characters, seed.symbols, seed.exam_tips, seed.access_level
from (values
  ('shushanikis-tsameba', 'შუშანიკის წამება', 'იაკობ ხუცესი', 'hagiography', 'ტექსტი აღწერს შუშანიკის სარწმუნოებრივ არჩევანსა და ვარსქენის ძალადობრივ მოქმედებას. ნაწარმოები რწმენის, ღირსებისა და პიროვნული სიმტკიცის კონფლიქტზეა აგებული.', '[]'::jsonb, null, null, '[]'::jsonb, ARRAY['რწმენა', 'ღირსება', 'ძალაუფლება']::text[], ARRAY['შუშანიკი', 'ვარსქენი', 'იაკობ ხუცესი']::text[], ARRAY['საპყრობილე', 'ჯვარი']::text[], ARRAY['პასუხში დაასახელეთ ტექსტის მთავარი კონფლიქტი და დაუკავშირეთ ავტორის ეპოქას.', 'ესესთვის გამოიყენეთ ერთი კონკრეტული ეპიზოდი და ახსენით, როგორ წარმოაჩენს ის მთავარ იდეას.']::text[], 'free'),
